import * as THREE from 'https://cdn.jsdelivr.net/npm/three@0.184.0/build/three.module.js';
import { GLTFLoader } from 'https://cdn.jsdelivr.net/npm/three@0.184.0/examples/jsm/loaders/GLTFLoader.js';

// Anatomical source: “Stylized Human Brain”, Poly by Google, CC BY.
const brainGlbBase64 = '';
const canvas = document.getElementById('brain3d');

if (canvas) {
  const reducedMotion = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
  const scene = new THREE.Scene();
  const camera = new THREE.PerspectiveCamera(29, 1, .1, 30);
  camera.position.set(0, 0, 6.7);

  const renderer = new THREE.WebGLRenderer({ canvas, alpha: true, antialias: true, powerPreference: 'low-power' });
  renderer.setClearColor(0x000000, 0);
  renderer.setPixelRatio(Math.min(window.devicePixelRatio || 1, 1.35));
  renderer.outputColorSpace = THREE.SRGBColorSpace;

  const brain = new THREE.Group();
  brain.rotation.set(-.08, -.22, -.03);
  scene.add(brain);

  const cyan = 0x00dfff;
  const blue = 0x087cff;
  const bytes = Uint8Array.from(atob(brainGlbBase64), (character) => character.charCodeAt(0));
  const loader = new GLTFLoader();

  loader.parse(bytes.buffer, '', (gltf) => {
    const source = gltf.scene;
    const box = new THREE.Box3().setFromObject(source);
    const center = box.getCenter(new THREE.Vector3());
    const size = box.getSize(new THREE.Vector3());
    source.updateMatrixWorld(true);
    const fitScale = 2.75 / size.x;

    source.traverse((child) => {
      if (!child.isMesh) return;
      const geometry = child.geometry.clone();
      geometry.applyMatrix4(child.matrixWorld);
      geometry.translate(-center.x, -center.y, -center.z);
      geometry.scale(fitScale, fitScale, fitScale);
      const surface = new THREE.Mesh(geometry, new THREE.MeshBasicMaterial({
        color: blue,
        transparent: true,
        opacity: .09,
        depthWrite: false,
        side: THREE.DoubleSide,
        blending: THREE.AdditiveBlending
      }));
      const wires = new THREE.LineSegments(new THREE.WireframeGeometry(geometry), new THREE.LineBasicMaterial({
        color: cyan,
        transparent: true,
        opacity: .52,
        depthWrite: false,
        blending: THREE.AdditiveBlending
      }));
      const nodes = new THREE.Points(geometry, new THREE.PointsMaterial({
        color: 0xa9f8ff,
        size: .022,
        transparent: true,
        opacity: .92,
        depthWrite: false,
        blending: THREE.AdditiveBlending
      }));
      const neuralSurface = new THREE.Group();
      neuralSurface.add(surface, wires, nodes);
      brain.add(neuralSurface);
    });
  });

  const chipMaterial = new THREE.MeshBasicMaterial({ color: cyan, transparent: true, opacity: .86, blending: THREE.AdditiveBlending });
  const chip = new THREE.Mesh(new THREE.BoxGeometry(.15, .15, .15), chipMaterial);
  chip.add(new THREE.LineSegments(new THREE.EdgesGeometry(chip.geometry), new THREE.LineBasicMaterial({ color: 0xe5ffff })));
  chip.position.set(.02, -.02, .05);
  brain.add(chip);

  const discharge = new THREE.Line(
    new THREE.BufferGeometry().setFromPoints([
      new THREE.Vector3(.02, -.02, .05),
      new THREE.Vector3(.24, .16, .13),
      new THREE.Vector3(.46, .06, .2),
      new THREE.Vector3(.72, .31, .18),
      new THREE.Vector3(.96, .22, .12)
    ]),
    new THREE.LineBasicMaterial({ color: cyan, transparent: true, opacity: 0, blending: THREE.AdditiveBlending })
  );
  brain.add(discharge);

  function resize() {
    const rect = canvas.getBoundingClientRect();
    renderer.setSize(rect.width, rect.height, false);
    camera.aspect = rect.width / rect.height;
    camera.updateProjectionMatrix();
  }

  let pointerX = 0;
  let pointerY = 0;
  window.addEventListener('pointermove', (event) => {
    pointerX = event.clientX / window.innerWidth - .5;
    pointerY = event.clientY / window.innerHeight - .5;
  }, { passive: true });
  window.addEventListener('resize', resize, { passive: true });
  resize();

  function animate(time = 0) {
    const seconds = time * .001;
    if (!reducedMotion) {
      brain.rotation.y = -.22 + seconds * .13 + pointerX * .16;
      brain.rotation.x += ((-.08 - pointerY * .08) - brain.rotation.x) * .025;
    }
    const pulse = .64 + Math.sin(seconds * 4.6) * .27;
    chip.scale.setScalar(.9 + pulse * .22);
    chipMaterial.opacity = pulse;
    discharge.material.opacity = Math.max(0, Math.sin(seconds * 1.25) - .91) * 7;
    renderer.render(scene, camera);
    if (!reducedMotion) requestAnimationFrame(animate);
  }
  animate();
}
